import{_ as e,c as a,o as i,a1 as o}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"版本日誌：功能更新 | OpenSkills","description":"查看 OpenSkills 版本變更歷史，了解 update 指令、符號連結、私有倉庫等新功能，以及路徑遍歷防護等重要改進和問題修復。","frontmatter":{"title":"版本日誌：功能更新 | OpenSkills","sidebarTitle":"看看新功能","subtitle":"版本日誌：功能更新 | OpenSkills","description":"查看 OpenSkills 版本變更歷史，了解 update 指令、符號連結、私有倉庫等新功能，以及路徑遍歷防護等重要改進和問題修復。","tags":["changelog","version history"],"order":1},"headers":[],"relativePath":"zh-tw/numman-ali/openskills/changelog/changelog/index.md","filePath":"zh-tw/numman-ali/openskills/changelog/changelog/index.md"}'),r={name:"zh-tw/numman-ali/openskills/changelog/changelog/index.md"};function t(n,l,s,d,h,c){return i(),a("div",null,[...l[0]||(l[0]=[o('<h1 id="更新日誌" tabindex="-1">更新日誌 <a class="header-anchor" href="#更新日誌" aria-label="Permalink to &quot;更新日誌&quot;">​</a></h1><p>本頁面記錄 OpenSkills 的版本變更歷史，幫助你了解每個版本的新功能、改進和問題修復。</p><hr><h2 id="_1-5-0-2026-01-17" tabindex="-1">[1.5.0] - 2026-01-17 <a class="header-anchor" href="#_1-5-0-2026-01-17" aria-label="Permalink to &quot;[1.5.0] - 2026-01-17&quot;">​</a></h2><h3 id="新增功能" tabindex="-1">新增功能 <a class="header-anchor" href="#新增功能" aria-label="Permalink to &quot;新增功能&quot;">​</a></h3><ul><li><strong><code>openskills update</code></strong> - 從記錄的來源重新整理已安裝技能（預設：全部重新整理）</li><li><strong>源元數據追蹤</strong> - 安裝時現在記錄來源資訊，用於可靠地更新技能</li></ul><h3 id="改進" tabindex="-1">改進 <a class="header-anchor" href="#改進" aria-label="Permalink to &quot;改進&quot;">​</a></h3><ul><li><strong>多技能讀取</strong> - <code>openskills read</code> 指令現在支援逗號分隔的技能名稱列表</li><li><strong>生成使用說明</strong> - 優化了 shell 環境下的 read 指令呼叫提示</li><li><strong>README</strong> - 新增了更新指南和人工使用提示</li></ul><h3 id="問題修復" tabindex="-1">問題修復 <a class="header-anchor" href="#問題修復" aria-label="Permalink to &quot;問題修復&quot;">​</a></h3><ul><li><strong>更新體驗優化</strong> - 跳過沒有源元數據的技能，並列出這些技能提示重新安裝</li></ul><hr><h2 id="_1-4-0-2026-01-17" tabindex="-1">[1.4.0] - 2026-01-17 <a class="header-anchor" href="#_1-4-0-2026-01-17" aria-label="Permalink to &quot;[1.4.0] - 2026-01-17&quot;">​</a></h2><h3 id="改進-1" tabindex="-1">改進 <a class="header-anchor" href="#改進-1" aria-label="Permalink to &quot;改進&quot;">​</a></h3><ul><li><strong>README</strong> - 明確專案本地預設安裝方式，移除冗餘的 sync 提示</li><li><strong>安裝訊息</strong> - 安裝程式現在明確區分專案本地預設安裝與 <code>--global</code> 選項</li></ul><hr><h2 id="_1-3-2-2026-01-17" tabindex="-1">[1.3.2] - 2026-01-17 <a class="header-anchor" href="#_1-3-2-2026-01-17" aria-label="Permalink to &quot;[1.3.2] - 2026-01-17&quot;">​</a></h2><h3 id="改進-2" tabindex="-1">改進 <a class="header-anchor" href="#改進-2" aria-label="Permalink to &quot;改進&quot;">​</a></h3><ul><li><strong>文件與 AGENTS.md 指引</strong> - 所有指令範例和生成的使用說明統一使用 <code>npx openskills</code></li></ul><hr><h2 id="_1-3-1-2026-01-17" tabindex="-1">[1.3.1] - 2026-01-17 <a class="header-anchor" href="#_1-3-1-2026-01-17" aria-label="Permalink to &quot;[1.3.1] - 2026-01-17&quot;">​</a></h2><h3 id="問題修復-1" tabindex="-1">問題修復 <a class="header-anchor" href="#問題修復-1" aria-label="Permalink to &quot;問題修復&quot;">​</a></h3><ul><li><strong>Windows 安裝</strong> - 修復了 Windows 系統上的路徑驗證問題（&quot;Security error: Installation path outside target directory&quot;）</li><li><strong>CLI 版本</strong> - <code>npx openskills --version</code> 現在正確讀取 package.json 中的版本號</li><li><strong>根目錄 SKILL.md</strong> - 修復了 SKILL.md 在倉庫根目錄的單技能倉庫安裝問題</li></ul><hr><h2 id="_1-3-0-2025-12-14" tabindex="-1">[1.3.0] - 2025-12-14 <a class="header-anchor" href="#_1-3-0-2025-12-14" aria-label="Permalink to &quot;[1.3.0] - 2025-12-14&quot;">​</a></h2><h3 id="新增功能-1" tabindex="-1">新增功能 <a class="header-anchor" href="#新增功能-1" aria-label="Permalink to &quot;新增功能&quot;">​</a></h3><ul><li><p><strong>符號連結支援</strong> - 技能現在可以透過符號連結安裝到技能目錄 (<a href="https://github.com/numman-ali/openskills/issues/3" target="_blank" rel="noreferrer">#3</a>)</p><ul><li>支援透過從複製倉庫建立符號連結來實現基於 git 的技能更新</li><li>支援本地技能開發工作流程</li><li>損壞的符號連結會被優雅地跳過</li></ul></li><li><p><strong>可配置輸出路徑</strong> - sync 指令新增 <code>--output</code> / <code>-o</code> 選項 (<a href="https://github.com/numman-ali/openskills/issues/5" target="_blank" rel="noreferrer">#5</a>)</p><ul><li>可同步到任意 <code>.md</code> 檔案（如 <code>.ruler/AGENTS.md</code>）</li><li>如果檔案不存在，自動建立檔案並新增標題</li><li>如果需要，自動建立巢狀目錄</li></ul></li><li><p><strong>本地路徑安裝</strong> - 支援從本地目錄安裝技能 (<a href="https://github.com/numman-ali/openskills/issues/10" target="_blank" rel="noreferrer">#10</a>)</p><ul><li>支援絕對路徑（<code>/path/to/skill</code>）</li><li>支援相對路徑（<code>./skill</code>、<code>../skill</code>）</li><li>支援波浪號擴充（<code>~/my-skills/skill</code>）</li></ul></li><li><p><strong>私有 git 倉庫支援</strong> - 支援從私有倉庫安裝技能 (<a href="https://github.com/numman-ali/openskills/issues/10" target="_blank" rel="noreferrer">#10</a>)</p><ul><li>SSH URLs（<code>git@github.com:org/private-skills.git</code>）</li><li>帶認證的 HTTPS URLs</li><li>自動使用系統 SSH 金鑰</li></ul></li><li><p><strong>全面的測試套件</strong> - 跨 6 個測試檔案的 88 個測試</p><ul><li>符號連結偵測、YAML 解析的單元測試</li><li>install、sync 指令的整合測試</li><li>完整 CLI 工作流程的端對端測試</li></ul></li></ul><h3 id="改進-3" tabindex="-1">改進 <a class="header-anchor" href="#改進-3" aria-label="Permalink to &quot;改進&quot;">​</a></h3><ul><li><p><strong><code>--yes</code> 標誌現在跳過所有提示</strong> - 完全非互動模式，適用於 CI/CD (<a href="https://github.com/numman-ali/openskills/issues/6" target="_blank" rel="noreferrer">#6</a>)</p><ul><li>覆寫現有技能時不提示</li><li>跳過提示時顯示 <code>Overwriting: &lt;skill-name&gt;</code> 訊息</li><li>所有指令現在都可以在無頭環境中執行</li></ul></li><li><p><strong>CI 工作流程重排</strong> - 建置步驟現在在測試之前執行</p><ul><li>確保 <code>dist/cli.js</code> 存在，用於端對端測試</li></ul></li></ul><h3 id="安全性" tabindex="-1">安全性 <a class="header-anchor" href="#安全性" aria-label="Permalink to &quot;安全性&quot;">​</a></h3><ul><li><strong>路徑遍歷防護</strong> - 驗證安裝路徑保持在目標目錄內</li><li><strong>符號連結解參照</strong> - <code>cpSync</code> 使用 <code>dereference: true</code> 安全地複製符號連結目標</li><li><strong>非貪婪 YAML 正則</strong> - 防止 frontmatter 解析中潛在的 ReDoS 攻擊</li></ul><hr><h2 id="_1-2-1-2025-10-27" tabindex="-1">[1.2.1] - 2025-10-27 <a class="header-anchor" href="#_1-2-1-2025-10-27" aria-label="Permalink to &quot;[1.2.1] - 2025-10-27&quot;">​</a></h2><h3 id="問題修復-2" tabindex="-1">問題修復 <a class="header-anchor" href="#問題修復-2" aria-label="Permalink to &quot;問題修復&quot;">​</a></h3><ul><li>README 文件清理 - 移除了重複部分和錯誤的標誌</li></ul><hr><h2 id="_1-2-0-2025-10-27" tabindex="-1">[1.2.0] - 2025-10-27 <a class="header-anchor" href="#_1-2-0-2025-10-27" aria-label="Permalink to &quot;[1.2.0] - 2025-10-27&quot;">​</a></h2><h3 id="新增功能-2" tabindex="-1">新增功能 <a class="header-anchor" href="#新增功能-2" aria-label="Permalink to &quot;新增功能&quot;">​</a></h3><ul><li><code>--universal</code> 標誌，將技能安裝到 <code>.agent/skills/</code> 而非 <code>.claude/skills/</code><ul><li>適用於多代理環境（Claude Code + Cursor/Windsurf/Aider）</li><li>避免與 Claude Code 原生市集外掛衝突</li></ul></li></ul><h3 id="改進-4" tabindex="-1">改進 <a class="header-anchor" href="#改進-4" aria-label="Permalink to &quot;改進&quot;">​</a></h3><ul><li>專案本地安裝現在是預設選項（之前是全域安裝）</li><li>技能預設安裝到 <code>./.claude/skills/</code></li></ul><hr><h2 id="_1-1-0-2025-10-27" tabindex="-1">[1.1.0] - 2025-10-27 <a class="header-anchor" href="#_1-1-0-2025-10-27" aria-label="Permalink to &quot;[1.1.0] - 2025-10-27&quot;">​</a></h2><h3 id="新增功能-3" tabindex="-1">新增功能 <a class="header-anchor" href="#新增功能-3" aria-label="Permalink to &quot;新增功能&quot;">​</a></h3><ul><li>全面的單頁 README，包含技術深度解析</li><li>與 Claude Code 的並列對比</li></ul><h3 id="問題修復-3" tabindex="-1">問題修復 <a class="header-anchor" href="#問題修復-3" aria-label="Permalink to &quot;問題修復&quot;">​</a></h3><ul><li>位置標籤現在根據安裝位置正確顯示 <code>project</code> 或 <code>global</code></li></ul><hr><h2 id="_1-0-0-2025-10-26" tabindex="-1">[1.0.0] - 2025-10-26 <a class="header-anchor" href="#_1-0-0-2025-10-26" aria-label="Permalink to &quot;[1.0.0] - 2025-10-26&quot;">​</a></h2><h3 id="新增功能-4" tabindex="-1">新增功能 <a class="header-anchor" href="#新增功能-4" aria-label="Permalink to &quot;新增功能&quot;">​</a></h3><ul><li>初始發布</li><li><code>npx openskills install &lt;source&gt;</code> - 從 GitHub 倉庫安裝技能</li><li><code>npx openskills sync</code> - 為 AGENTS.md 生成 <code>&lt;available_skills&gt;</code> XML</li><li><code>npx openskills list</code> - 顯示已安裝的技能</li><li><code>npx openskills read &lt;name&gt;</code> - 為代理載入技能內容</li><li><code>npx openskills manage</code> - 互動式技能刪除</li><li><code>npx openskills remove &lt;name&gt;</code> - 刪除指定技能</li><li>所有指令的互動式 TUI 介面</li><li>支援 Anthropic 的 SKILL.md 格式</li><li>漸進式揭露（按需載入技能）</li><li>打包資源支援（references/、scripts/、assets/）</li></ul><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th></tr></thead><tbody><tr><td>更新日誌原文</td><td><a href="https://github.com/numman-ali/openskills/blob/main/CHANGELOG.md" target="_blank" rel="noreferrer"><code>CHANGELOG.md</code></a></td></tr></tbody></table></details>',53)])])}const m=e(r,[["render",t]]);export{g as __pageData,m as default};
